const body = $input.first().json.body;

if (body.type === 'url_verification') {
  return [];
}

const event = body.event || {};

if (event.bot_id || event.subtype === 'bot_message') {
  return [];
}

if (!event.thread_ts && !(event.text && event.text.includes('<@'))) {
  return [];
}

return [{
  json: {
    channel: event.channel,
    thread_ts: event.thread_ts || event.ts,
    user: event.user,
    text: event.text
  }
}];

const channel = $('Filter Events').first().json.channel;
const text = $('Filter Events').first().json.text || '';

const channelMap = {
  'C0ALLJWR1HV': 'ea',
  'C0ALLEKR9FZ': 'engineering',
  'C0AM2310P8A': 'strategy',
  'C0AMWB887KJ': 'engineering'
};

let persona = channelMap[channel] || 'ea';

if (channel === 'C0AM01NHQ3Y') {
  const lower = text.toLowerCase();
  if (/cost|spend|burn|budget/.test(lower)) persona = 'cfo';
  else if (/legal|compliance|efin|privacy/.test(lower)) persona = 'legal';
  else if (/partner|outreach|deal/.test(lower)) persona = 'partnerships';
  else if (/tax|irs|filing|deduction|refund/.test(lower)) persona = 'tax-domain';
  else if (/design|ux|ui|mobile/.test(lower)) persona = 'ux';
  else if (/pr |deploy|code|bug|test/.test(lower)) persona = 'engineering';
  else persona = 'ea';
}

const personaConfig = {
  'ea': { file: 'ea.mdc', username: 'EA / Operator', icon: ':clipboard:' },
  'engineering': { file: 'engineering.mdc', username: 'Engineering', icon: ':gear:' },
  'strategy': { file: 'strategy.mdc', username: 'Strategy', icon: ':chess_pawn:' },
  'legal': { file: 'legal.mdc', username: 'Legal', icon: ':scales:' },
  'cfo': { file: 'cfo.mdc', username: 'Finance', icon: ':chart_with_upwards_trend:' },
  'qa': { file: 'qa.mdc', username: 'QA', icon: ':mag:' },
  'growth': { file: 'growth.mdc', username: 'Growth', icon: ':rocket:' },
  'social': { file: 'social.mdc', username: 'Social', icon: ':speech_balloon:' },
  'tax-domain': { file: 'tax-domain.mdc', username: 'Tax Domain', icon: ':receipt:' },
  'cpa': { file: 'cpa.mdc', username: 'CPA Advisor', icon: ':bar_chart:' },
  'partnerships': { file: 'partnerships.mdc', username: 'Partnerships', icon: ':handshake:' },
  'ux': { file: 'ux.mdc', username: 'UX Lead', icon: ':art:' }
};

const config = personaConfig[persona] || personaConfig['ea'];
return [{ json: { persona, ...config } }];

const threadResponse = $('Fetch Thread History').first().json;
const messages = (threadResponse.messages || []).map(m => {
  const role = m.bot_id ? 'Assistant' : 'User';
  return `${role}: ${m.text}`;
}).join('\n\n');

const rulesRaw = $('Fetch Persona Rules').first().json;
const rulesText = typeof rulesRaw === 'string' ? rulesRaw : (rulesRaw.data || JSON.stringify(rulesRaw));

const persona = $('Route Persona').first().json;

const systemPrompt = `You are the ${persona.username} persona for Paperwork Labs. Respond in Slack mrkdwn format (*bold*, bullet points with •, _italic_). Be concise and actionable.\n\n--- PERSONA RULES ---\n${rulesText}\n--- END RULES ---`;

const userMessage = `Thread conversation:\n\n${messages}\n\nRespond to the latest message in the thread.`;

return [{ json: { systemPrompt, userMessage, persona } }];
